CREATE OR REPLACE FUNCTION public.update_sale_probe(_sale_id uuid) RETURNS uuid LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ DECLARE _sale RECORD; _it RECORD; _shop_id UUID; _old_customer_id UUID; BEGIN SELECT * INTO _sale FROM public.sales WHERE id = _sale_id FOR UPDATE; IF _sale IS NULL THEN RAISE EXCEPTION 'not found'; END IF; _shop_id := _sale.shop_id; _old_customer_id := _sale.customer_id; FOR _it IN SELECT * FROM public.sale_items WHERE sale_id = _sale_id LOOP PERFORM public.apply_stock_movement(_shop_id, _it.product_id, 'return_in', _it.quantity, _it.unit_cost, 'sale_edit_reverse', _sale_id, 'edit'); END LOOP; IF _old_customer_id IS NOT NULL AND _sale.due > 0 THEN UPDATE public.customers SET current_balance = current_balance - _sale.due WHERE id = _old_customer_id AND shop_id = _shop_id; END IF; DELETE FROM public.sale_items WHERE sale_id = _sale_id; DELETE FROM public.installment_schedules WHERE sale_id = _sale_id; DELETE FROM public.customer_payments WHERE sale_id = _sale_id; RETURN _sale_id; END; $$;